import{G as a,c as e,b as t,ae as n}from"./chunks/framework.Cpb2nuHT.js";const _=JSON.parse('{"title":"synchronized关键字","description":"","frontmatter":{"title":"synchronized关键字","date":"2024/7/30","tags":["Java","并发","多线程"],"author":"花木凋零成兰"},"headers":[],"relativePath":"MisNotes/Synchronized关键字.md","filePath":"MisNotes/Synchronized关键字.md","lastUpdated":1722516194000}'),r={name:"MisNotes/Synchronized关键字.md"};function i(d,o,s,c,h,l){return t(),e("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1722297600000"},[...o[0]||(o[0]=[n('<h1 id="synchronized-关键字" tabindex="-1">synchronized 关键字 <a class="header-anchor" href="#synchronized-关键字" aria-label="Permalink to &quot;synchronized 关键字&quot;">​</a></h1><p>synchronized 是可重入锁,</p><h2 id="底层实现原理" tabindex="-1">底层实现原理 <a class="header-anchor" href="#底层实现原理" aria-label="Permalink to &quot;底层实现原理&quot;">​</a></h2><p>底层语义通过一个 monitor(监视器锁) 的对象来完成, 每个 Java 对象都有一个关联的监视器锁(monitor); 每个 synchronized 修饰过的代码当它的 monitor 被占用时就会处于锁定状态并且尝试获取 monitor 的所有权;</p><p><strong>基本过程：</strong></p><ol><li>如果 monitor 的进入数为0, 则该线程进入monitor, 然后将进入数设置为1, 即该线程为 monitor 的所有者;</li><li>如果线程已经占有该 monitor, 只是重新进入, 则进入 monitor 的进入数加1;</li><li>如果其他线程已经占用了 monitor, 则该线程进入阻塞状态, 直到 monitor 的进入数为0, 再重新尝试获取 monitor 的所有权;</li></ol><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2>',7)])])}const p=a(r,[["render",i]]);export{_ as __pageData,p as default};
